async function mockApiCall<T>(url: string, timeout: number = 3000): Promise<T> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => reject(new Error(`Timeout: ${url}`)), timeout);

    // 模拟网络延迟
    setTimeout(() => {
      clearTimeout(timer);
      // 模拟成功返回（实际开发中此处为 fetch 调用）
      if (url === '/api/user') resolve({ id: '1', name: 'John Doe', email: 'john@example.com' } as any);
      if (url === '/api/orders') resolve([{ id: 'o1', amount: 100, status: 'completed' }] as any);
      if (url === '/api/metrics') resolve({ activeUsers: 1200, revenue: 5000, conversionRate: 0.05 } as any);
      else reject(new Error('404 Not Found'));
    }, 500);
  });
}

/**
 * 核心方法：并发请求并实现优雅降级
 */
async function fetchDashboardData(): Promise<DashboardData> {
  /**
   * 策略：将每个 Promise 包装在一个 catch 块中。
   * 这样即使某个请求失败，Promise.all 也会继续执行，
   * 最终返回的结果中，失败的部分将为 null 而不是抛出异常。
   */
  const requestTasks = [
    mockApiCall<User>('/api/user').catch((err) => {
      console.error('Failed to fetch user data:', err.message);
      return null;
    }),
    mockApiCall<Order[]>('/api/orders').catch((err) => {
      console.error('Failed to fetch orders data:', err.message);
      return null;
    }),
    mockApiCall<Metrics>('/api/metrics').catch((err) => {
      console.error('Failed to fetch metrics data:', err.message);
      return null;
    }),
  ];

  try {
    const [user, orders, metrics] = await Promise.all(requestTasks);

    return {
      user,
      orders,
      metrics,
    };
  } catch (error) {
    // 理论上由于内部已 catch，此处不会进入，但作为防御性编程保留
    console.error('Unexpected error in Promise.all:', error);
    return { user: null, orders: null, metrics: null };
  }
}

// --- 测试执行 ---
(async () => {
  console.log('Fetching dashboard data...');
  const data = await fetchDashboardData();
  console.log('Dashboard Data Result:', JSON.stringify(data, null, 2));
})();
